export function getSeedSales(): Sale[] {
  return raw.map(([date, clientName, leadSource, closer, sdr, status, paymentMethod, product, grossValue, netValue]) => ({
    id: crypto.randomUUID(),
    date: parseDate(date),
    clientName,
    product: productMap[product] || product,
    grossValue,
    netValue,
    paymentMethod,
    closer,
    sdr,
    status: statusMap[status] || status,
    leadSource,
    notes: "",
  }));
}
